INSERT INTO "prompt_template" ("id", "title", "content", "category", "tags", "needsReference", "sortOrder") VALUES
('tpl-voxel', '体素 3D 图标', '将图片 / 描述 / emoji 转换为体素（Voxel）3D 图标风格，Octane 渲染，8k，干净纯色背景，居中构图，立体感强。', '风格转换', '["体素","3D","图标","图生图"]', 1, 19),
('tpl-enamel-pin', '珐琅徽章', '将附图中的人物转换成可爱的珐琅徽章风格。使用光亮金属描边和鲜艳的珐琅填色，不添加任何额外元素。方形效果图格式，白色背景。', '风格转换', '["徽章","珐琅","可爱","图生图"]', 1, 20),
('tpl-flat-sticker', '扁平 Q版贴纸', '把这张照片设计成一个极简扁平插画风格的Q版贴纸，厚白边，保留人物特征，风格可爱，人物要超出圆形区域边框，圆形区域为纯色不要3d感，透明背景。', '风格转换', '["贴纸","扁平","Q版","图生图"]', 1, 21),
('tpl-chibi-sticker', 'Chibi 表情包六连', '创作一套全新的 chibi sticker，共六个独特姿势，以参考人物形象为主角：1.比剪刀手俏皮眨眼；2.泪眼汪汪可爱哭泣；3.张开双臂热情拥抱；4.侧卧入睡带甜甜微笑；5.自信指向前方点缀闪亮特效；6.飞吻飘散爱心。保留 chibi 美学：夸张大眼、柔和面部线条、活泼发型，背景使用充满活力的纯色并搭配星星或彩色纸屑装饰，适当留白。比例 9:16。', '风格转换', '["表情包","chibi","贴纸","图生图"]', 1, 22),
('tpl-anime-comic', '日系双格漫画', '创建一张日系萌系双格漫画，上下排列。将参考人物转换为日系萌系卡通形象，保留服饰、发型、五官等细节。第一格表情委屈托腮配文字框，第二格暴怒拍桌、场景一片狼藉。文字采用简洁可爱手写体，构图饱满生动，适当留白，图片比例 2:3，色彩鲜艳突出卡通风格。', '风格转换', '["漫画","日系","卡通","图生图"]', 1, 23),
('tpl-ootd', '角色职业 OOTD', '为图片人物生成不同职业风的 OOTD 时尚穿搭和配饰，与人物色系一致的纯色背景，Q版 3D，C4D 渲染，保持人脸特征与姿势一致，腿部修长。构图 9:16，顶部文字 OOTD，左侧为人物 Q版形象，右侧为穿搭单件展示。', '风格转换', '["OOTD","穿搭","Q版","图生图"]', 1, 24),
('tpl-russian-doll', 'Q版俄罗斯套娃', '把图片人物变成 Q 版可爱俄罗斯套娃，从大到小一共五个，放在精致的木桌上，横幅 3:2 比例，柔和布光。', '风格转换', '["套娃","Q版","可爱","图生图"]', 1, 25),
('tpl-double-exposure', '双重曝光', '融合、混合、叠加的双重曝光图像。将人物剪影与自然风光（松树林、山峰、河流、孤独的旅人）和谐地交织在一起，剪影内部呈现充满活力的全彩色景观，简洁分明的单色背景保持锐利对比，将焦点吸引到层次丰富的双重曝光上，线条清晰刻意，细节丰富。', '风格转换', '["双重曝光","艺术","创意","文生图"]', 0, 26),
('tpl-mini-building', '迷你 3D 创意建筑', '3D Q版迷你风格，一个充满奇趣的迷你建筑，外观像一个巨大的产品造型。建筑两层，大玻璃窗展示内部温馨精致的设计：木质家具、温暖灯光与忙碌的人物。街道上有可爱的小人偶漫步，四周布置长凳、街灯和植物盆栽。整体采用城市微缩景观风格，细节丰富逼真，光线柔和，呈现午后惬意感受。', '微缩·场景', '["微缩","3D","建筑","文生图"]', 0, 27),
('tpl-tiltshift-scene', '移轴微缩场景', '微型立体场景呈现，运用移轴摄影的技法，呈现出 Q版【场景主题】，玩具般的元素，高解析度 CG，戏剧化光线，色彩鲜明，强调景深与拟真微观视角，仿佛俯瞰一个玩具世界。', '微缩·场景', '["移轴","微缩","Q版","文生图"]', 0, 28),
('tpl-crystalball-story', '水晶球故事场景', '一枚精致的水晶球静静摆放在窗边温暖柔和的桌面上，背景虚化朦胧，暖色调阳光穿透水晶球折射出点点金光。水晶球内部呈现一个以【主题】为主题的迷你立体世界，细腻梦幻的 3D 景观，人物与物体皆是可爱 Q版造型，彼此充满灵动的情感互动。整体氛围充满东亚奇幻色彩，魔幻现实主义般的奇妙质感，温馨柔和的光芒。', '微缩·场景', '["水晶球","3D","梦幻","文生图"]', 0, 29),
('tpl-paper-diorama', '折叠纸雕立体绘本', '多层折叠式纸雕立体绘本，放在书桌上，背景纯净突出主题，绘本呈现立体翻页书风格，比例 3:2 横版。翻开的书页呈现【场景主题】，所有元素皆可精细折叠组合，逼真细腻的纸张折叠质感，正面视角，视觉风格梦幻唯美，色彩缤纷绚丽，充满奇幻生动的故事氛围。', '微缩·场景', '["纸雕","立体","绘本","文生图"]', 0, 30),
('tpl-silicone-wrist', 'Q版硅胶护腕托', '一个可爱 Q版的硅胶护腕托，外形基于【🐼】表情，柔软食品级硅胶材质，亲肤哑光质感，内部慢回弹棉，拟人化卡通风格，表情生动，双手张开趴在桌面呈拥抱手腕姿势，整体圆润软萌，治愈可爱，白色纯色背景，柔和布光，产品摄影风格，45 度俯视，高清细节。', '3D·手办', '["周边","硅胶","可爱","文生图"]', 0, 31),
('tpl-keychain', '定制 Q版钥匙串', '一张特写照片，展示一个被人手握住的可爱多彩钥匙串。钥匙串造型为参考主体的 Q 版风格，由柔软橡胶材质制成，带粗黑描边，连接在小巧的银色钥匙圈上，背景为中性色调。', '3D·手办', '["钥匙串","Q版","周边","图生图"]', 1, 32),
('tpl-crystalball-couple', '情侣水晶球', '将附图中的人物转换成水晶球场景。整体环境：水晶球放在窗边桌面上，背景模糊暖色调，阳光透过球体洒下点点金光。水晶球内部：人物为可爱 Q版 3D 造型，相互之间满眼爱意。', '3D·手办', '["水晶球","情侣","Q版","图生图"]', 1, 33),
('tpl-plain-selfie', '平凡感手机自拍', '一张极其平凡无奇的手机自拍照，没有明确主体或构图感，像随手一拍的快照。照片略带运动模糊，光线不均导致轻微曝光过度，角度尴尬、构图混乱，整体呈现刻意的平庸感，仿佛从口袋掏手机时不小心拍到。', '人像·摄影', '["自拍","写实","随手拍","文生图"]', 0, 34),
('tpl-magazine-cover', '时尚杂志封面', '一位人物以高清细节质感呈现，类似时尚杂志封面设计，照片上方中央标有文字 FASHION DESIGN。精致的造型与配饰，画面背景采用简约纯浅灰色以突出人物主体，专业影棚光照。', '人像·摄影', '["杂志","封面","时尚","文生图"]', 0, 35),
('tpl-out-screen', '透视出屏 3D 效果', '超写实，从上往下俯视角拍摄，一个时尚模特站在一部被人托起的智能手机屏幕上，营造强烈的透视错觉，强调人物从手机中站出来的三维效果。手机屏幕处理成深色舞台。使用强烈的强制透视表现手掌、手机与人物之间的比例差异，背景干净灰色，柔和室内光，浅景深，超现实写实合成，透视特别强。', '人像·摄影', '["透视","3D","创意","文生图"]', 0, 36),
('tpl-surreal-pencil', '素描中的彩色主体', '一幅铅笔素描画，描绘了主体 1 与主体 2 互动的场景，其中主体 2 以逼真的全彩风格呈现，与主体 1 及背景的手绘素描风格形成超现实的对比。', '创意·设计', '["素描","超现实","创意","文生图"]', 0, 37),
('tpl-treasure-map', '古代藏宝图', '将图像转换为绘制在古老羊皮纸上的古代藏宝图。地图包含详细元素：海洋上的帆船、海岸线上的古老港口或城堡、通向标记宝藏地点大 X 的虚线路径、山脉、棕榈树和装饰性的罗盘玫瑰。整体风格让人联想到旧时的海盗冒险电影。', '创意·设计', '["地图","复古","创意","图生图"]', 1, 38),
('tpl-keycap-brand', '品牌机械键帽', '一个超逼真的 3D 渲染图，展示四个机械键盘键帽排列成紧密的 2x2 网格，所有键帽相互接触，等轴测角度。一个键帽透明印有文字，另外三个采用不同颜色，其中一个带有品牌 Logo。逼真的塑料纹理，圆润雕刻键帽，柔和阴影，干净的浅灰色背景。', '创意·设计', '["键帽","品牌","3D","文生图"]', 0, 39),
('tpl-chrome-badge', '镀铬 Emoji 徽章', '高精度的 3D 渲染图，按照 emoji 图标展示一个金属质感徽章，固定在竖直的商品卡片上，超光滑镀铬质感和圆润 3D 图标造型，风格化未来主义设计，柔和反光与干净阴影。纸质卡片顶部中央带欧式挂孔，徽章上方是醒目标题，下方配趣味标语。背景柔和灰色，柔光摄影棚灯光，极简风格。', '创意·设计', '["徽章","镀铬","3D","文生图"]', 0, 40),
('tpl-coloring-page', '儿童涂色线描页', '一张黑白线描涂色插画，适合直接打印在标准尺寸纸张上，无纸张边框。整体风格清新简洁，使用清晰流畅的黑色轮廓线条，无阴影、无灰阶、无颜色填充，背景纯白便于涂色。在右下角用小图生成一个完整的彩色版本供参考。画面描述：【一只独角兽在森林草地上漫步，阳光明媚蓝天白云】。', '创意·设计', '["线描","涂色","儿童","文生图"]', 0, 41),
('tpl-letter-fusion', '字母含义融合', '在字母中融入单词的含义，将图形和字母巧妙融合在一起。单词：{ beautify }。下面加上单词的简要说明。', '创意·设计', '["字母","创意","排版","文生图"]', 0, 42),
('tpl-jsoncard', '代码风格名片', '特写镜头：一只手正拿着一张设计成 VS Code 中 JSON 文件外观的名片，名片上的代码以真实的 JSON 语法高亮格式呈现。窗口界面包含典型工具栏图标和标题栏，标题显示为 Business Card.json，整体风格与 VS Code 一致。背景略微虚化，突出名片内容。名片 JSON 包含 name、title、email、link 字段。', '创意·设计', '["名片","代码","创意","文生图"]', 0, 43),
('tpl-lego-city', '乐高城市景观', '创建一幅高度精细且色彩鲜艳的乐高版城市地标景象。前景用乐高砖块精致还原经典建筑立面，乐高小人们沿街漫步、拍照、观光，街道停靠经典样式乐高汽车。背景是壮观的江景与现代摩天大楼群，造型逼真色彩丰富。天空为乐高明亮蓝色，点缀白色乐高积木云朵，整体充满活力与现代感。', '创意·设计', '["乐高","城市","创意","文生图"]', 0, 44),
('tpl-bookshelf-logo', 'Logo 造型创意书架', '拍摄一张现代书架的照片，造型灵感来源于某个 Logo 的形状。书架由流畅互相连接的曲线构成，形成多个大小不一的分区，材质为光滑哑光黑色金属，曲线内部设木质层板，柔和暖色 LED 灯带勾勒内侧曲线轮廓。书架安装在中性色调墙面上，摆放彩色书籍、小型绿植和极简艺术摆件，整体富有创意、优雅且略带未来感。', '创意·设计', '["书架","Logo","产品","文生图"]', 0, 45),
('tpl-vector-poster', '城市矢量艺术海报', '生成一张夏季的彩色矢量艺术海报，顶部有大的城市名标题，下方有较小的国家名标题，扁平鲜艳的配色，简洁的几何插画风格，呈现旅行招贴海报质感。', '创意·设计', '["海报","矢量","旅行","文生图"]', 0, 46),
('tpl-cloud-art', '云彩造型艺术', '生成一张照片，捕捉白天的场景，天空中散落的云彩组成了【主体 / 物体】的形状，位于【地点】的上方，自然光照，真实摄影质感。', '创意·设计', '["云彩","创意","摄影","文生图"]', 0, 47),
('tpl-passport-stamp', '护照入境印章', '创建一个逼真的护照页，并盖上【城市, 国家】的入境章。章面以粗体英文写明欢迎语，设计成圆形或椭圆形并带装饰性边框，包含 ARRIVAL 字样和一个日期，章面中加入当地地标的微妙轮廓作为背景细节。使用深蓝色或红色墨水并略加晕染，章面略微倾斜如手工压印。护照页清晰可见纸张纹理和安全图案。', '创意·设计', '["护照","印章","复古","文生图"]', 0, 48),
('tpl-rpg-card', 'RPG 角色收藏卡', '创建一张 RPG 收藏风格的数字角色卡。角色自信地站立，配有与其职业相关的工具或符号，以 3D 卡通风格呈现，柔和光照，鲜明个性。添加技能条或属性数值，卡片顶部添加标题横幅，底部放置角色名牌，边框干净利落如同真实收藏公仔包装盒，背景与职业主题相匹配，配色使用温暖高光。', '创意·设计', '["卡牌","RPG","角色","文生图"]', 0, 49),
('tpl-info-card', '手绘信息图卡片', '创作一张手绘风格的信息图卡片，比例 9:16 竖版，背景为带纸质肌理的米白色，质朴亲切的手绘美感。上方以红黑相间对比鲜明的大号毛笔草书字体突出标题，文字分 2 至 4 个清晰小节，每节用简短精炼的中文短语表达要点。卡片中点缀简单有趣的手绘插画或图标，整体布局视觉平衡，预留足够留白，简洁易读。', '创意·设计', '["信息图","手绘","卡片","文生图"]', 0, 50),
('tpl-fantasy-illust', '奇幻卡通插画', '一个卡通风格的角色，开心地跳跃穿过一个发光的蓝色圆形传送门，背景是一片郁郁葱葱的奇幻森林：高大的树木、蘑菇、鲜花、宁静的河流、漂浮的岛屿，以及充满氛围的星夜天空与多个月亮。整体明亮鲜艳的色彩搭配柔和光效，奇幻插画风。', '创意·设计', '["插画","奇幻","卡通","文生图"]', 0, 51),
('tpl-film-island', '胶片风格飞行岛屿', '35 毫米胶片风格的照片：一座城市漂浮在天空中的飞行岛屿上，怀旧胶片颗粒质感，柔和自然光，电影感构图。', '创意·设计', '["胶片","奇幻","场景","文生图"]', 0, 52),
('tpl-soft-3d-ad', '柔和 3D 产品广告', '一个柔和的 3D 卡通风格【品牌产品】雕塑，由光滑的粘土般纹理和鲜艳的柔和色彩制成，放置在简约的等距场景中，场景与产品特性相得益彰，构图简洁，光线柔和，阴影微妙，产品徽标和三个词的口号清晰显示在下方。', '创意·设计', '["广告","3D","产品","文生图"]', 0, 53),
('tpl-pokemon', '原创精灵生物', '根据提供的物体照片创作一个原创生物，看起来像属于一个奇幻怪物捕捉宇宙，受复古日式 RPG 怪物艺术影响，可爱或酷炫设计。图像包含：生物全身视图，灵感来自物体的形状、材料或用途；脚边一个自定义设计的小球体或胶囊；为生物发明的名字显示在旁边或下方；其元素类型基于物体核心属性。线条清晰，阴影柔和，富有表现力。', '创意·设计', '["生物","原创","奇幻","图生图"]', 1, 54),
('tpl-emoji-icecream', 'Emoji 奶油雪糕', '将一个 Emoji 变成一根奶油雪糕，奶油在雪糕顶上呈曲线流动状看起来美味可口，45 度悬浮在空中，Q版 3D 可爱风格，一致色系的纯色背景。', '趣味·Emoji', '["Emoji","3D","可爱","文生图"]', 0, 55),
('tpl-emoji-silk', 'Emoji 丝绸宇宙', '将一个 Emoji 变成一个柔软的 3D 丝绸质感物体，表面包裹顺滑流动的丝绸面料，带超现实褶皱细节、柔和高光与阴影，轻轻漂浮在干净的浅灰色背景中央，超现实、触感十足且现代，工作室灯光，高分辨率渲染。', '趣味·Emoji', '["Emoji","丝绸","3D","文生图"]', 0, 56),
('tpl-emoji-fluffy', 'Emoji 毛茸茸物体', '将一个简单平面的矢量图标转化为柔软、立体、毛茸茸的可爱物体，整体被浓密真实的毛发完全覆盖，带柔和阴影，居中悬浮于干净的浅灰色背景中轻盈漂浮，超现实富有触感和现代感，摄影棚级灯光，高分辨率渲染，比例 1:1。', '趣味·Emoji', '["Emoji","毛绒","可爱","文生图"]', 0, 57),
('tpl-emoji-inflatable', 'Emoji 充气物体', '创建一个高分辨率 3D 渲染图，将一个 Emoji 设计成充气、鼓胀的物体，形状柔软圆润充满空气，类似毛绒气球或充气玩具。光滑哑光材质，带细微布料折痕和缝线，整体略带不规则且柔软塌陷，柔和阴影和软光照突出体积感，置于干净简约的浅色背景，俏皮而具雕塑感。', '趣味·Emoji', '["Emoji","充气","3D","文生图"]', 0, 58),
('tpl-emoji-paper', 'Emoji 纸艺图标', '一个纸艺风格的 Emoji 图标，漂浮在纯白背景上，由彩色剪纸手工制作，具有可见的纸张纹理、折痕和分层形状，下方投下柔和阴影营造轻盈立体感。整体简洁有趣干净，图像居中周围留白，柔和影棚光照突出纸张质感与边缘。', '趣味·Emoji', '["Emoji","纸艺","图标","文生图"]', 0, 59),
('tpl-emoji-rug', 'Emoji 簇绒地毯', '创建一张图像，展示一个彩色手工簇绒的地毯，形状为某个 Emoji，铺设在简约地板背景上。设计大胆俏皮，柔软蓬松质感和粗线条细节，从上方俯拍自然光照，略带古怪的 DIY 美感，色彩鲜艳，轮廓卡通化，材质温馨舒适。', '趣味·Emoji', '["Emoji","地毯","DIY","文生图"]', 0, 60),
('tpl-emoji-pixel', '8 位像素 Emoji 图标', '创建一个极简主义的 8 位像素风格图标，居中放置在纯白背景上，使用有限的复古调色板，搭配像素化细节、锐利边缘和干净的块状形态，简洁具标志性，灵感来自经典街机游戏美学。', '趣味·Emoji', '["Emoji","像素","复古","文生图"]', 0, 61),
('tpl-emoji-planter', '创意造型花盆', '一张高质量的照片，展示一个可爱的陶瓷【物体 / 动物】形状花盆，表面光滑，里面装满各种生机勃勃的多肉植物和绿色植物，花盆带一个友好的面孔，放置在柔和的中性背景上，漫射自然光照明，细腻的纹理和色彩对比，构图简洁极具简约风格。', '趣味·Emoji', '["花盆","可爱","产品","文生图"]', 0, 62);
